<script>
import { ref } from "vue"
let timer = 0
export default {
    props: {
        type: String,
        message: String | Function,
        Close: Function,
        countdown: Number,
    },
    data() {
        return {
            show: false,
            remain: 0
        }
    },
    mounted() {
        window.setTimeout(() => {
            this.show = true
        }, 0)
        if (this.countdown) {
            this.remain = this.countdown
            const tick = () => {
                if (this.show && this.remain > 0) {
                    this.remain = this.remain - 1;
                    timer = window.setTimeout(tick, 1000);
                }
            }
            timer = window.setTimeout(tick, 1000);
        }
    },
    computed: {
        Message() {
            return this.message + (this.countdown ? (" " + this.remain + "s") : "")
        }
    },
    methods: {
        Stop() {
            if (this.type != 'loading') {
                this.show = false
                if (timer != 0) {
                    clearTimeout(timer)
                }
                this.Close()
            }
        },
    },
}
</script>
<style lang="scss" scoped>
@keyframes turn {
    0% {
        -webkit-transform: rotate(0deg);
    }
    100% {
        -webkit-transform: rotate(360deg);
    }
}

.toast {
    position: fixed;
    top: 50%;
