    border-radius: 8px;
    transform: translate3d(-50%, -50%, 0);
    z-index: 9999;
    transition: 0.3s;
    cursor: pointer;

    div.icon {
        width: 50px;
        height: 50px;
        margin: 15px 0;
        background: none !important;

        svg {
            width: 100%;
            height: 100%;

            path {
                fill: #fff;
            }
        }
    }

    .loading {
        animation: turn 1s steps(12, end) infinite;
    }

    .message {
        display: block;
        width: 100%;
        flex: 0 0 100%;
        word-wrap: break-word;
    }
}
